from microbit import *

while True:
    argia = display.read_light_level()  # 0-255
    temp  = temperature()               # Celsius graduak

    display.scroll('A:' + str(argia) + ' T:' + str(temp), delay=60)

    if argia < 50:
        display.show(Image.ASLEEP)     # Oso ilun
    elif temp > 28:
        display.show(Image.SURPRISED)  # Bero handia
    else:
        display.show(Image.HAPPY)
    sleep(1500)

