# Botoi erraldoiak pinekin
from microbit import *

# 0 eta 1 pinak sarrera gisa (botoiak)
# 0 pina GND-ra konektatu botoi HANDIA sakatzeko (adib: pintza 0 pinera, beste bat GND/P0-ra)
# 1 pina GND-ra konektatu botoi HANDIA sakatzeko (adib: pintza 1 pinera, beste bat GND/P1-ra)

while True:
    if pin0.is_touched(): # Pina GND-ra konektatuta dagoen detektatzen du (sakatuta)
        display.show(Image.YES)
    elif pin1.is_touched():
        display.show(Image.NO)
    else:
        display.clear()
    sleep(50)
